import { useState } from "react";
import { useAuth } from "../AuthContext";   // ✅ using your AuthContext

function Login({ setSuccessMessage }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState(""); // not stored, just form input
  const { login } = useAuth();

  const handleSubmit = (e) => {
    e.preventDefault();
    // Later: replace with API call for real authentication
    login(username);
    setSuccessMessage("✅ Login successful!");
  };

  return (
    <div>
      <h2>Login</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Enter username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />
        <input
          type="password"
          placeholder="Enter password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button type="submit">Login</button>
      </form>
    </div>
  );
}

export default Login;
